// LESSON: Reference Page 1 - Generics.
// You will learn: Use type parameters and bounds to keep collection code type-safe.
class Prog2Reference432 {
  // EXEMPEL 1: En generisk klass kan lagra en typ som valjs vid anvandning.
  static class Box<T> {
    private final T value;
    Box(T value) { this.value = value; }
    T get() { return value; }
  }
  // EXEMPEL 2: En generisk metod kan fungera for manga List-typer.
  static <T> T first(java.util.List<T> values) {
    return values.get(0);
  }
  // EXEMPEL 3: Wildcards beskriver om listan producerar eller tar emot varden.
  static double sum(java.util.List<? extends Number> numbers) {
    double total = 0;
    for (Number number : numbers) { total += number.doubleValue(); }
    return total;
  }
  static void addDefault(java.util.List<? super Integer> numbers) { numbers.add(1); }
}
